25	export function buildInputField(field: DMMF.SchemaArg, context: GenerateContext, source?: string): ts.Property {
26	  const tsType = buildAllFieldTypes(field.inputTypes, context, source)
27	
28	  const tsProperty = ts.property(field.name, field.isRequired ? tsType : appendSkipType(context, tsType))
29	  if (!field.isRequired) {
30	    tsProperty.optional()
31	  }
32	  const docComment = ts.docComment()
33	  if (field.comment) {
34	    docComment.addText(field.comment)
35	  }
36	  if (field.deprecation) {
37	    docComment.addText(`@deprecated since ${field.deprecation.sinceVersion}: ${field.deprecation.reason}`)
38	  }
39	
40	  if (docComment.lines.length > 0) {
41	    tsProperty.setDocComment(docComment)
42	  }
43	
44	  return tsProperty
