47	function buildSingleFieldType(t: DMMF.InputTypeRef, genericsInfo: GenericArgsInfo, source?: string): ts.TypeBuilder {
48	  let type: ts.NamedType
49	
50	  const scalarType = GraphQLScalarToJSTypeTable[t.type]
51	  if (t.location === 'enumTypes' && t.namespace === 'model') {
52	    type = ts.namedType(`$Enums.${t.type}`)
53	  } else if (t.type === 'Null') {
54	    return ts.nullType
55	  } else if (Array.isArray(scalarType)) {
56	    const union = ts.unionType(scalarType.map(namedInputType))
57	    if (t.isList) {
58	      return union.mapVariants((variant) => ts.array(variant))
59	    }
60	    return union
61	  } else {
62	    type = namedInputType(scalarType ?? t.type)
63	  }
64	
65	  if (genericsInfo.typeRefNeedsGenericModelArg(t)) {
66	    if (source) {
67	      type.addGenericArgument(ts.stringLiteral(source))
68	    } else {
69	      type.addGenericArgument(ts.namedType('$PrismaModel'))
70	    }
71	  }
72	
73	  if (t.isList) {
74	    return ts.array(type)
75	  }
76	
77	  return type
78	}
