1	import type * as DMMF from '@prisma/dmmf'
2	import { hasOwnProperty } from '@prisma/internals'
3	import * as ts from '@prisma/ts-builders'
4	
5	import type { DMMFHelper } from '../dmmf'
6	import { getPayloadName } from '../utils'
7	import { GraphQLScalarToJSTypeTable, needsNamespace } from '../utils/common'
8	
9	export function buildModelOutputProperty(field: DMMF.Field, dmmf: DMMFHelper) {
10	  let fieldTypeName = hasOwnProperty(GraphQLScalarToJSTypeTable, field.type)
11	    ? GraphQLScalarToJSTypeTable[field.type]
12	    : field.type
13	  if (Array.isArray(fieldTypeName)) {
14	    fieldTypeName = fieldTypeName[0]
15	  }
16	
17	  if (needsNamespace(field)) {
18	    fieldTypeName = `Prisma.${fieldTypeName}`
19	  }
20	  let fieldType: ts.TypeBuilder
21	  if (field.kind === 'object') {
22	    const payloadType = ts.namedType(getPayloadName(field.type))
23	    if (!dmmf.isComposite(field.type)) {
24	      payloadType.addGenericArgument(ts.namedType('ExtArgs'))
25	    }
26	    fieldType = payloadType
27	  } else if (field.kind === 'enum') {
28	    fieldType = ts.namedType(`$Enums.${fieldTypeName}`)
29	  } else {
30	    fieldType = ts.namedType(fieldTypeName)
31	  }
32	
33	  if (field.isList) {
34	    fieldType = ts.array(fieldType)
35	  } else if (!field.isRequired) {
36	    fieldType = ts.unionType(fieldType).addVariant(ts.nullType)
37	  }
38	  const property = ts.property(field.name, fieldType)
39	  if (field.documentation) {
40	    property.setDocComment(ts.docComment(field.documentation))
41	  }
42	  return property
43	}
44	
45	export function buildOutputType(type: DMMF.OutputType) {
46	  return ts.moduleExport(ts.typeDeclaration(type.name, ts.objectType().addMultiple(type.fields.map(buildOutputField))))
47	}
48	
49	function buildOutputField(field: DMMF.SchemaField) {
50	  let fieldType: ts.TypeBuilder
51	
52	  if (field.outputType.location === 'enumTypes' && field.outputType.namespace === 'model') {
53	    fieldType = ts.namedType(enumTypeName(field.outputType))
54	  } else {
55	    const typeNames = GraphQLScalarToJSTypeTable[field.outputType.type] ?? field.outputType.type
56	    fieldType = Array.isArray(typeNames) ? ts.namedType(typeNames[0]) : ts.namedType(typeNames)
57	  }
58	
59	  if (field.outputType.isList) {
60	    fieldType = ts.array(fieldType)
61	  } else if (field.isNullable) {
62	    fieldType = ts.unionType(fieldType).addVariant(ts.nullType)
63	  }
64	
65	  const property = ts.property(field.name, fieldType)
66	  if (field.deprecation) {
67	    property.setDocComment(
68	      ts.docComment(`@deprecated since ${field.deprecation.sinceVersion} because ${field.deprecation.reason}`),
69	    )
70	  }
71	
72	  return property
73	}
74	
75	function enumTypeName(ref: DMMF.OutputTypeRef) {
76	  const name = ref.type
77	  const namespace = ref.namespace === 'model' ? '$Enums' : 'Prisma'
78	  return `${namespace}.${name}`
79	}
