import path from 'node:path'

import { BuildOptions } from './build'

type AdapterEntry = {
  entry: string
  outfile: string
}

export function createAdapterConfig(entries: AdapterEntry[]): BuildOptions[] {
  return entries.flatMap(({ entry, outfile }) => {
    const baseName = path.basename(outfile)

    return [
      {
        name: `${baseName}-cjs`,
        format: 'cjs' as const,
        bundle: true,
        entryPoints: [entry],
        outfile,
        outExtension: { '.js': '.js' },
        emitTypes: true,
      },
      {
        name: `${baseName}-esm`,
        format: 'esm' as const,
        bundle: true,
        entryPoints: [entry],
        outfile,
        outExtension: { '.js': '.mjs' },
        emitTypes: true,
      },
    ]
  })
}

export const adapterConfig = createAdapterConfig([{ entry: 'src/index.ts', outfile: 'dist/index' }])

export const unbundledConfig: BuildOptions[] = [
  {
    name: 'cjs',
    format: 'cjs',
    entryPoints: ['src/**/*.ts'],
    outdir: 'dist',
    outExtension: { '.js': '.js' },
    emitTypes: true,
  },
  {
    name: 'esm',
    format: 'esm',
    entryPoints: ['src/**/*.ts'],
    outdir: 'dist',
    outExtension: { '.js': '.mjs' },
    emitTypes: true,
  },
]
```

**Two config types:**
- **`adapterConfig`**: Uses bundled format (single entry point, creates both .js and .mjs)
- **`unbundledConfig`**: Unbundled format (multiple entry points, creates tree of output files)

For **generator packages**, use `adapterConfig` pattern (bundled with single entry point).

