import type * as DMMF from '@prisma/dmmf'
import * as ts from '@prisma/ts-builders'
import { stringify } from '@prisma/ts-builders'

/**
 * Generates `enums.ts` — one union type alias per Prisma enum, e.g.
 * `export type Role = 'ADMIN' | 'USER'`
 */
export function generateEnumsFile(enums: readonly DMMF.DatamodelEnum[]): string {
  const f = ts.file()

  for (const enumDef of enums) {
    const unionType = ts.unionType(enumDef.values.map((v) => ts.stringLiteral(v.name)))
    f.add(ts.moduleExport(ts.typeDeclaration(enumDef.name, unionType)))
  }

  return stringify(f)
}

