/**
 * Generates `client.ts` — the `RestApiClient` class with one typed delegate
 * property per model, a private `#request` helper that uses `fetch`, and a
 * `#extractUniqueId` helper that pulls the first value from a WhereUniqueInput.
 */
export function generateRestClientFile(mappings: readonly DMMF.ModelMapping[]): string {
  const routes = mappings.map(toModelRoute)

  const delegateFields = routes
    .map(({ propertyName, modelName }) => {
      return `  readonly ${propertyName}: {
    findMany(args?: { where?: ${modelName}WhereInput }): Promise<${modelName}[]>
    findUnique(args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName} | null>
    create(args: { data: ${modelName}CreateInput }): Promise<${modelName}>
    update(args: { where: ${modelName}WhereUniqueInput; data: ${modelName}UpdateInput }): Promise<${modelName}>
    delete(args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName}>
  }`
    })
    .join('\n\n')

  const constructorAssignments = routes
    .map(({ propertyName, ...rest }) => {
      return `    this.${propertyName} = ${buildDelegate({ propertyName, ...rest })}`
    })
    .join('\n\n')

  return `${buildImports(routes)}

