import type * as DMMF from '@prisma/dmmf'

import { generateEnumsFile } from './generate-enums'
import { generateModelTypesFile } from './generate-model-types'
import { generateRestClientFile } from './generate-rest-client'
import type { FileMap } from './write-files'

/**
 * Builds the complete set of files that make up the generated REST API client.
 *
 * Returned paths are relative to the generator output directory:
 * - `enums.ts`                  — union type aliases for every Prisma enum
 * - `types/<Model>.ts`          — per-model interface + CRUD arg types
 * - `types/index.ts`            — barrel re-exporting all model type files
 * - `client.ts`                 — `RestApiClient` class with typed delegates
 * - `index.ts`                  — top-level barrel
 */
export function generateClient(dmmf: DMMF.Document): FileMap {
  const { models, enums } = dmmf.datamodel
  const mappings = dmmf.mappings.modelOperations

  const enumNames = new Set(enums.map((e) => e.name))

  const files: FileMap = {}

  // enums.ts
  if (enums.length > 0) {
    files['enums.ts'] = generateEnumsFile(enums)
  }

  // types/<Model>.ts
  for (const model of models) {
    files[`types/${model.name}.ts`] = generateModelTypesFile(model, enumNames)
  }

  // types/index.ts
  const typeBarrelLines = models.map((m) => `export * from './${m.name}'`)
  if (enums.length > 0) {
    typeBarrelLines.push(`export * from '../enums'`)
  }
  files['types/index.ts'] = typeBarrelLines.join('\n') + '\n'

  // client.ts
  files['client.ts'] = generateRestClientFile(mappings)

  // index.ts
  const indexLines = [`export * from './client'`, `export * from './types/index'`]
  if (enums.length > 0) {
    indexLines.push(`export * from './enums'`)
  }
  files['index.ts'] = indexLines.join('\n') + '\n'

  return files
}

