 * relation fields are expressed as references to the related model type.
 */
function fieldToTsType(field: DMMF.Field, enumNames: Set<string>): ts.TypeBuilder {
  let base: ts.TypeBuilder

  if (field.kind === 'enum') {
    base = ts.namedType(field.type)
  } else if (field.kind === 'object') {
    base = ts.namedType(field.type)
  } else {
    const mapped = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
    base = ts.namedType(mapped)
  }

  if (field.isList) {
    base = ts.array(base)
  }

  // Nullable non-list fields can be null at the database level
  if (!field.isRequired && !field.isList) {
    base = ts.unionType([base, ts.nullType])
  }

  return base
}

/**
 * Builds the `interface User { ... }` declaration for a model, including all
 * scalar, enum, and relation fields.
 */
function buildModelInterface(model: DMMF.Model, enumNames: Set<string>): ts.Export<ts.InterfaceDeclaration> {
  const iface = ts.interfaceDeclaration(model.name)

  for (const field of model.fields) {
    const tsType = fieldToTsType(field, enumNames)
    const prop = ts.property(field.name, tsType)
    if (!field.isRequired || field.isList) {
      // Lists are always present but may be empty; nullable scalars are optional
      if (!field.isRequired && !field.isList) {
        prop.optional()
      }
    }
    iface.add(prop)
  }

  return ts.moduleExport(iface)
}

/**
 * `UserWhereInput` — all model fields as optional, used for filtering.
 * Relation fields are excluded (filtering happens on scalar/enum columns).
 */
function buildWhereInput(model: DMMF.Model, enumNames: Set<string>): ts.Export<ts.TypeDeclaration> {
  const obj = ts.objectType()

  for (const field of model.fields) {
    if (field.kind === 'object') continue
    const tsType = fieldToTsType(field, enumNames)
    obj.add(ts.property(field.name, tsType).optional())
  }

  return ts.moduleExport(ts.typeDeclaration(`${model.name}WhereInput`, obj))
}

/**
 * `UserWhereUniqueInput` — only `@id` and `@unique` fields, used for
 * single-record lookups and mutations.
 */
function buildWhereUniqueInput(model: DMMF.Model, enumNames: Set<string>): ts.Export<ts.TypeDeclaration> {
  const obj = ts.objectType()

  for (const field of model.fields) {
    if (!field.isId && !field.isUnique) continue
    const tsType = fieldToTsType(field, enumNames)
    obj.add(ts.property(field.name, tsType).optional())
  }

  return ts.moduleExport(ts.typeDeclaration(`${model.name}WhereUniqueInput`, obj))
}

/**
 * `UserCreateInput` — writable scalar and enum fields.
 * Fields with `hasDefaultValue` or that are not required are optional.
 * Relation, read-only, and @updatedAt fields are omitted.
 */
function buildCreateInput(model: DMMF.Model, enumNames: Set<string>): ts.Export<ts.TypeDeclaration> {
  const obj = ts.objectType()

  for (const field of model.fields) {
    if (isWriteOnlyExcluded(field)) continue
    const tsType = fieldToTsType(field, enumNames)
    const prop = ts.property(field.name, tsType)
    if (field.hasDefaultValue || !field.isRequired) {
      prop.optional()
    }
    obj.add(prop)
  }

  return ts.moduleExport(ts.typeDeclaration(`${model.name}CreateInput`, obj))
}

/**
 * `UserUpdateInput` — same writable fields as CreateInput but all optional
 * (PATCH semantics: send only the fields you want to change).
 */
function buildUpdateInput(model: DMMF.Model, enumNames: Set<string>): ts.Export<ts.TypeDeclaration> {
  const obj = ts.objectType()

  for (const field of model.fields) {
    if (isWriteOnlyExcluded(field)) continue
    const tsType = fieldToTsType(field, enumNames)
    obj.add(ts.property(field.name, tsType).optional())
  }

  return ts.moduleExport(ts.typeDeclaration(`${model.name}UpdateInput`, obj))
}

/**
 * Generates the complete `types/<Model>.ts` file containing:
 * - `interface <Model>`
 * - `type <Model>WhereInput`
 * - `type <Model>WhereUniqueInput`
 * - `type <Model>CreateInput`
 * - `type <Model>UpdateInput`
 *
 * Enum types are imported from the shared `../enums` barrel when the model
 * references any enum fields.
 */
export function generateModelTypesFile(model: DMMF.Model, enumNames: Set<string>): string {
  const f = ts.file()

  // Import enums referenced by this model
  const referencedEnums = model.fields.filter((field) => field.kind === 'enum' && enumNames.has(field.type))
  if (referencedEnums.length > 0) {
    const uniqueEnumTypes = [...new Set(referencedEnums.map((f) => f.type))]
    const imp = ts.moduleImport('../enums').named(uniqueEnumTypes[0])
    for (const enumType of uniqueEnumTypes.slice(1)) {
      ;(imp as ts.BindingsImport).named(enumType)
    }
    f.addImport(imp as ts.BindingsImport)
  }

  f.add(buildModelInterface(model, enumNames))
  f.add(buildWhereInput(model, enumNames))
  f.add(buildWhereUniqueInput(model, enumNames))
  f.add(buildCreateInput(model, enumNames))
  f.add(buildUpdateInput(model, enumNames))

  return stringify(f)
}

