import type * as DMMF from '@prisma/dmmf'

type ModelRoute = {
  /** Pascal-case model name, e.g. `User` */
  modelName: string
  /** Camel-case property name on the client, e.g. `user` */
  propertyName: string
  /** URL path segment, e.g. `users` */
  routePath: string
}

/**
 * Derives the three naming variants from a DMMF model mapping.
 * The plural comes from DMMF so it mirrors whatever the schema specifies.
 */
function toModelRoute(mapping: DMMF.ModelMapping): ModelRoute {
  const modelName = mapping.model
  const propertyName = modelName.charAt(0).toLowerCase() + modelName.slice(1)
  const routePath = mapping.plural.toLowerCase()
  return { modelName, propertyName, routePath }
}

/**
 * Generates the import block at the top of `client.ts`.
 */
function buildImports(routes: ModelRoute[]): string {
  const lines: string[] = []

  if (routes.length > 0) {
    lines.push(`import type {`)
    for (const { modelName } of routes) {
      lines.push(`  ${modelName},`)
      lines.push(`  ${modelName}WhereInput,`)
      lines.push(`  ${modelName}WhereUniqueInput,`)
      lines.push(`  ${modelName}CreateInput,`)
      lines.push(`  ${modelName}UpdateInput,`)
    }
    lines.push(`} from './types/index'`)
  }

  return lines.join('\n')
}

/**
 * Generates the inline object literal that forms one model delegate, e.g.
 * the value assigned to `this.user = { findMany(...) { ... }, ... }`.
 */
function buildDelegate(route: ModelRoute): string {
  const { modelName, routePath } = route
  return `    {
      findMany: (args?: { where?: ${modelName}WhereInput }): Promise<${modelName}[]> =>
        this.#request('GET', '/${routePath}', args?.where),

      findUnique: (args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName} | null> =>
        this.#request('GET', \`/${routePath}/\${this.#extractUniqueId(args.where)}\`, undefined),

      create: (args: { data: ${modelName}CreateInput }): Promise<${modelName}> =>
        this.#request('POST', '/${routePath}', args.data),

      update: (args: { where: ${modelName}WhereUniqueInput; data: ${modelName}UpdateInput }): Promise<${modelName}> =>
        this.#request('PATCH', \`/${routePath}/\${this.#extractUniqueId(args.where)}\`, args.data),

      delete: (args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName}> =>
        this.#request('DELETE', \`/${routePath}/\${this.#extractUniqueId(args.where)}\`, undefined),
    }`
}

/**
 * Generates `client.ts` — the `RestApiClient` class with one typed delegate
 * property per model, a private `#request` helper that uses `fetch`, and a
 * `#extractUniqueId` helper that pulls the first value from a WhereUniqueInput.
 */
export function generateRestClientFile(mappings: readonly DMMF.ModelMapping[]): string {
  const routes = mappings.map(toModelRoute)

  const delegateFields = routes
    .map(({ propertyName, modelName }) => {
      return `  readonly ${propertyName}: {
    findMany(args?: { where?: ${modelName}WhereInput }): Promise<${modelName}[]>
    findUnique(args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName} | null>
    create(args: { data: ${modelName}CreateInput }): Promise<${modelName}>
    update(args: { where: ${modelName}WhereUniqueInput; data: ${modelName}UpdateInput }): Promise<${modelName}>
    delete(args: { where: ${modelName}WhereUniqueInput }): Promise<${modelName}>
  }`
    })
    .join('\n\n')

  const constructorAssignments = routes
    .map(({ propertyName, ...rest }) => {
      return `    this.${propertyName} = ${buildDelegate({ propertyName, ...rest })}`
    })
    .join('\n\n')

  return `${buildImports(routes)}

export type RestApiClientOptions = {
  /** Base URL of the REST API, e.g. \`https://api.example.com\` */
  baseUrl: string
  /** Optional headers sent with every request, e.g. \`{ Authorization: 'Bearer ...' }\` */
  headers?: Record<string, string>
}

export class RestApiClient {
  readonly #baseUrl: string
  readonly #headers: Record<string, string>

${delegateFields}

  constructor(options: RestApiClientOptions) {
    this.#baseUrl = options.baseUrl.replace(/\\/$/, '')
    this.#headers = options.headers ?? {}

${constructorAssignments}
  }

  async #request(method: string, path: string, body: unknown): Promise<any> {
    const init: RequestInit = {
      method,
      headers: {
        'Content-Type': 'application/json',
        ...this.#headers,
      },
    }

    if (body !== undefined) {
      init.body = JSON.stringify(body)
    }

    const response = await fetch(\`\${this.#baseUrl}\${path}\`, init)

    if (!response.ok) {
      throw new Error(\`REST API request failed: \${response.status} \${response.statusText}\`)
    }

    // 204 No Content has no body
    if (response.status === 204) {
      return null
    }

    return response.json() as Promise<unknown>
  }

  /** Extracts the first value from a WhereUniqueInput to use as a URL path segment. */
  #extractUniqueId(where: Record<string, unknown>): string {
    const entries = Object.entries(where).filter(([, v]) => v !== undefined)
    if (entries.length === 0) {
      throw new Error('WhereUniqueInput must contain at least one defined field')
    }
    return String(entries[0][1])
  }
}
`
}

import type * as DMMF from '@prisma/dmmf'

import { generateEnumsFile } from './generate-enums'
import { generateModelTypesFile } from './generate-model-types'
import { generateRestClientFile } from './generate-rest-client'
import type { FileMap } from './write-files'

/**
 * Builds the complete set of files that make up the generated REST API client.
 *
 * Returned paths are relative to the generator output directory:
 * - `enums.ts`                  — union type aliases for every Prisma enum
 * - `types/<Model>.ts`          — per-model interface + CRUD arg types
 * - `types/index.ts`            — barrel re-exporting all model type files
 * - `client.ts`                 — `RestApiClient` class with typed delegates
 * - `index.ts`                  — top-level barrel
 */
export function generateClient(dmmf: DMMF.Document): FileMap {
  const { models, enums } = dmmf.datamodel
  const mappings = dmmf.mappings.modelOperations

  const enumNames = new Set(enums.map((e) => e.name))

  const files: FileMap = {}

  // enums.ts
  if (enums.length > 0) {
    files['enums.ts'] = generateEnumsFile(enums)
  }

  // types/<Model>.ts
  for (const model of models) {
    files[`types/${model.name}.ts`] = generateModelTypesFile(model, enumNames)
  }

  // types/index.ts
  const typeBarrelLines = models.map((m) => `export * from './${m.name}'`)
  if (enums.length > 0) {
    typeBarrelLines.push(`export * from '../enums'`)
  }
  files['types/index.ts'] = typeBarrelLines.join('\n') + '\n'

  // client.ts
  files['client.ts'] = generateRestClientFile(mappings)

  // index.ts
  const indexLines = [`export * from './client'`, `export * from './types/index'`]
  if (enums.length > 0) {
    indexLines.push(`export * from './enums'`)
  }
  files['index.ts'] = indexLines.join('\n') + '\n'

  return files
}

