import type * as DMMF from '@prisma/dmmf'
import * as ts from '@prisma/ts-builders'
import { stringify } from '@prisma/ts-builders'

import { SCALAR_TYPE_MAP } from './scalar-type-map'

/**
 * Returns true when a field should be excluded from write input types.
 * Relations, read-only fields, and @updatedAt fields are managed by the server.
 */
function isWriteExcluded(field: DMMF.Field): boolean {
  return field.kind === 'object' || field.isReadOnly || field.isUpdatedAt === true
}

/**
 * Maps a single DMMF field to the corresponding `@prisma/ts-builders` type.
 * Non-required non-list fields are represented as `T | null`.
 */
function fieldToTsType(field: DMMF.Field): ts.TypeBuilder {
  let base: ts.TypeBuilder

  if (field.kind === 'enum') {
    base = ts.namedType(field.type)
  } else if (field.kind === 'object') {
    base = ts.namedType(field.type)
  } else {
    base = ts.namedType(SCALAR_TYPE_MAP[field.type] ?? 'unknown')
  }

  if (field.isList) {
    return ts.array(base)
  }

  if (!field.isRequired) {
    return ts.unionType([base, ts.nullType])
  }

  return base
}

/**
 * Builds the `interface User { ... }` declaration for a model.
 * Relation fields are typed as optional because a REST endpoint may or may
 * not include related objects in the response payload.
 */
function buildModelInterface(model: DMMF.Model): ts.Export<ts.InterfaceDeclaration> {
  const iface = ts.interfaceDeclaration(model.name)

  for (const field of model.fields) {
    const prop = ts.property(field.name, fieldToTsType(field))
    if (field.kind === 'object') {
      prop.optional()
    }
    iface.add(prop)
  }

  return ts.moduleExport(iface)
}

/**
 * `UserWhereInput` — scalar and enum fields as optional, used for filtering.
 */
function buildWhereInput(model: DMMF.Model): ts.Export<ts.TypeDeclaration> {
  const obj = ts.objectType()

  for (const field of model.fields) {
    if (field.kind === 'object') continue
    obj.add(ts.property(field.name, fieldToTsType(field)).optional())
  }

  return ts.moduleExport(ts.typeDeclaration(`${model.name}WhereInput`, obj))
}

/**
 * `UserWhereUniqueInput` — only `@id` and `@unique` fields, for single-record
 * lookups and mutations.
 */
function buildWhereUniqueInput(model: DMMF.Model): ts.Export<ts.TypeDeclaration> {
  const obj = ts.objectType()

  for (const field of model.fields) {
    if (!field.isId && !field.isUnique) continue
    obj.add(ts.property(field.name, fieldToTsType(field)).optional())
  }

  return ts.moduleExport(ts.typeDeclaration(`${model.name}WhereUniqueInput`, obj))
}

/**
 * `UserCreateInput` — writable scalar and enum fields.
 * Fields with `hasDefaultValue` or that are not required are optional.
 */
function buildCreateInput(model: DMMF.Model): ts.Export<ts.TypeDeclaration> {
  const obj = ts.objectType()

  for (const field of model.fields) {
    if (isWriteExcluded(field)) continue
    const prop = ts.property(field.name, fieldToTsType(field))
    if (field.hasDefaultValue || !field.isRequired) {
      prop.optional()
    }
    obj.add(prop)
  }

  return ts.moduleExport(ts.typeDeclaration(`${model.name}CreateInput`, obj))
}

/**
 * `UserUpdateInput` — same writable fields as CreateInput but all optional
 * (PATCH semantics: only send the fields you want to change).
 */
function buildUpdateInput(model: DMMF.Model): ts.Export<ts.TypeDeclaration> {
  const obj = ts.objectType()

  for (const field of model.fields) {
    if (isWriteExcluded(field)) continue
    obj.add(ts.property(field.name, fieldToTsType(field)).optional())
  }

  return ts.moduleExport(ts.typeDeclaration(`${model.name}UpdateInput`, obj))
}

/**
 * Generates the complete `types/<Model>.ts` file containing:
 * - `interface <Model>`
 * - `type <Model>WhereInput`
 * - `type <Model>WhereUniqueInput`
 * - `type <Model>CreateInput`
 * - `type <Model>UpdateInput`
 *
 * Enum types referenced by this model are imported from `../enums`.
 */
export function generateModelTypesFile(model: DMMF.Model, enumNames: Set<string>): string {
  const f = ts.file()

  const referencedEnumTypes = [
    ...new Set(model.fields.filter((field) => field.kind === 'enum' && enumNames.has(field.type)).map((f) => f.type)),
  ]

  if (referencedEnumTypes.length > 0) {
    const imp = ts.moduleImport('../enums').named(referencedEnumTypes[0])
    for (const enumType of referencedEnumTypes.slice(1)) {
      imp.named(enumType)
    }
    f.addImport(imp)
  }

  f.add(buildModelInterface(model))
  f.add(buildWhereInput(model))
  f.add(buildWhereUniqueInput(model))
  f.add(buildCreateInput(model))
  f.add(buildUpdateInput(model))

  return stringify(f)
}

